class MinStack {

    private Stack<Integer> mainStack;
    private Stack<Integer> minTrackerStack;

    public MinStack() {
        mainStack = new Stack<>();
        minTrackerStack = new Stack<>();
    }

    public void push(int valueToPush) {
        mainStack.push(valueToPush);

        // If the minTrackerStack is empty, the new value is the first minimum.
        if (minTrackerStack.isEmpty()) {
            minTrackerStack.push(valueToPush);
        } else {
            // Push the smaller of the new value and the current minimum onto the tracker.
            minTrackerStack.push(Math.min(valueToPush, minTrackerStack.peek()));
        }
