    public void pop() {
        // Removing from mainStack requires removing the corresponding minimum from tracker.
        if (!mainStack.isEmpty()) {
            mainStack.pop();
            minTrackerStack.pop();
        }
    }

    public int top() {
        // The top of the mainStack is the most recently added element.
        if (!mainStack.isEmpty()) {
            return mainStack.peek();
        }
        throw new RuntimeException("Stack is empty.");
    }

    public int getMin() {
        // The top of the minTrackerStack always holds the current minimum.
        if (!minTrackerStack.isEmpty()) {
            return minTrackerStack.peek();
        }
        throw new RuntimeException("Stack is empty.");
    }
